oxy_webhelp_navlinks = {"support_tunnels-d30753e1303":{"topics":[{"title":"Timeout setting for support tunnels","shortdesc":"<p class=\"shortdesc\">You can specify the duration for which a Rubrik support tunnel remains open by         setting either an inactivity timeout or an absolute timeout. Inactivity timeout resets with         any activity, and absolute timeout is fixed regardless of activity.<\/p>","href":"saas\/common\/support_tunnel_timeout_setting.html","attributes":{"data-id":"support_tunnel_timeout_setting"},"menu":{"hasChildren":false},"tocID":"support_tunnel_timeout_setting-d30753e1316","topics":[]},{"title":"Opening a support tunnel","shortdesc":"<p class=\"shortdesc\">Open a support tunnel on one or more Rubrik clusters to allow a Rubrik Support         engineer to access the clusters and resolve hardware or software issues.<\/p>","href":"saas\/common\/opening_a_support_tunnel.html","attributes":{"data-id":"opening_a_support_tunnel"},"menu":{"hasChildren":false},"tocID":"opening_a_support_tunnel-d30753e1327","topics":[]},{"title":"Closing a support tunnel","shortdesc":"<p class=\"shortdesc\">Close the support tunnel on one or more Rubrik clusters after the Rubrik Support         engineer resolves the hardware or software issues.<\/p>","href":"saas\/common\/closing_a_support_tunnel.html","attributes":{"data-id":"closing_a_support_tunnel"},"menu":{"hasChildren":false},"tocID":"closing_a_support_tunnel-d30753e1338","topics":[]},{"title":"Information available on the Support Tunnel page","shortdesc":"<p class=\"shortdesc\">Information about the details provided by the Support Tunnel page, including cluster         name, UUID, tunnel status, open nodes, open port, time opened, and time left.<\/p>","href":"saas\/common\/support_tunnel_page_available_info.html","attributes":{"data-id":"support_tunnel_page_available_info"},"menu":{"hasChildren":false},"tocID":"support_tunnel_page_available_info-d30753e1349","topics":[]}]}};